import { execution } from '@dynatrace-sdk/automation-utils';
import { problemsClient } from '@dynatrace-sdk/client-classic-environment-v2';

export default async function ({ executionId }) {
  const { input } = await fetch(`/platform/automation/v1/executions/${executionId}`).then((res) => res.json());

  try {
    if (input.closeComment && input.closeComment.trim() !== '') {
      await problemsClient.addCommentToProblem({
        problemId: input.problemId,
        body: { comment: input.closeComment }
      });
      console.log('Closure comment added');
    }

    await problemsClient.closeProblem({
      problemId: input.problemId
    });

    console.log(`Problem ${input.problemId} closed successfully`);

    return {
      problemId: input.problemId,
      closed: true,
      closureTime: new Date().toISOString(),
      message: 'Problem successfully closed'
    };
  } catch (error) {
    console.error('Error closing problem:', error);
    throw new Error(`Failed to close problem: ${error}`);
  }
}
